#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
XP = Path("lib/xp_progression.dart")
PUBSPEC = Path("pubspec.yaml")
TARGET = Path("lib/retention_system.dart")

RETENTION_B64 = """"""

def run(command):
    print("$ " + " ".join(command))
    return subprocess.run(command, check=True)

for path in [MAIN, XP, PUBSPEC]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

main = MAIN.read_text(encoding="utf-8")
xp = XP.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")

if "part 'retention_system.dart';" in main or TARGET.exists():
    raise SystemExit(
        "Günlük ve haftalık rota sistemi zaten kurulmuş görünüyor."
    )

required_main = [
    "part 'advanced_modes.dart';",
    "class CareerStatsService",
    "static Future<XpGainResult> recordAnswer({",
    "static Future<XpGainResult> recordMarathon({",
    "await GameplayBoostSettingsService.initialize();",
    "DailyChallengeHomeCard(",
    "Bilgi Rotası • Sürüm 1.24",
    "await XpProgressService.clear();",
]

for marker in required_main:
    if marker not in main:
        raise SystemExit(
            f"Beklenen main.dart bölümü bulunamadı: {marker}"
        )

required_xp = [
    "static Future<XpGainResult> recordAnswer({",
    "static Future<XpGainResult> _award(",
    "await _save(progress);",
]

for marker in required_xp:
    if marker not in xp:
        raise SystemExit(
            f"Beklenen xp_progression.dart bölümü "
            f"bulunamadı: {marker}"
        )

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)

if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

major, minor, patch, build = map(
    int,
    version_match.groups(),
)

if (major, minor) != (1, 24):
    raise SystemExit(
        "Bu paket 1.24.x sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {major}.{minor}.{patch}+{build}"
    )

new_version = f"1.25.0+{build + 1}"

backup_dir = Path(tempfile.mkdtemp(
    prefix="bilgi_rotasi_retention_"
))
committed = False

try:
    shutil.copy2(MAIN, backup_dir / "main.dart")
    shutil.copy2(XP, backup_dir / "xp_progression.dart")
    shutil.copy2(PUBSPEC, backup_dir / "pubspec.yaml")

    TARGET.write_text(
        base64.b64decode(RETENTION_B64).decode("utf-8"),
        encoding="utf-8",
    )

    main = main.replace(
        "part 'advanced_modes.dart';",
        "part 'advanced_modes.dart';\n"
        "part 'retention_system.dart';",
        1,
    )

    init_marker = """  try {
    await GameplayBoostSettingsService.initialize();
  } catch (_) {
    // Oynanış ayarları açılamasa bile oyun devam eder.
  }

  runApp(const BilgiRotasiApp());"""

    if init_marker not in main:
        raise RuntimeError(
            "Başlangıç sistemi ekleme noktası bulunamadı."
        )

    main = main.replace(
        init_marker,
        """  try {
    await GameplayBoostSettingsService.initialize();
  } catch (_) {
    // Oynanış ayarları açılamasa bile oyun devam eder.
  }

  try {
    await RetentionProgressService.initialize();
  } catch (_) {
    // Günlük ve haftalık sistem açılamasa bile oyun devam eder.
  }

  runApp(const BilgiRotasiApp());""",
        1,
    )

    answer_start = main.index(
        "  static Future<XpGainResult> recordAnswer({"
    )
    answer_end = main.index(
        "\n  static Future<XpGainResult> recordGameCompleted({",
        answer_start,
    )
    answer_block = main[answer_start:answer_end]

    answer_return = """    await _save(stats);

    return XpProgressService.recordAnswer(
      correct: correct,
      difficulty: difficulty,
      badgeEarned: badgeEarned,
      xpMultiplier: xpMultiplier,
    );"""

    if answer_return not in answer_block:
        raise RuntimeError(
            "recordAnswer entegrasyon noktası bulunamadı."
        )

    answer_block = answer_block.replace(
        answer_return,
        """    await _save(stats);

    final answerGain = await XpProgressService.recordAnswer(
      correct: correct,
      difficulty: difficulty,
      badgeEarned: badgeEarned,
      xpMultiplier: xpMultiplier,
    );

    final retentionGain =
        await RetentionProgressService.recordAnswer(
      categoryIndex: categoryIndex,
      correct: correct,
      difficulty: difficulty,
      currentStreak: answerGain.currentStreak,
    );

    if (retentionGain == null) return answerGain;

    return XpGainResult.combine(
      <XpGainResult>[answerGain, retentionGain],
      reason: '${answerGain.reason} + '
          '${retentionGain.reason}',
    );""",
        1,
    )

    main = (
        main[:answer_start]
        + answer_block
        + main[answer_end:]
    )

    marathon_start = main.index(
        "  static Future<XpGainResult> recordMarathon({"
    )
    marathon_end = main.index(
        "\n  static Future<void> clear()",
        marathon_start,
    )
    marathon_block = main[marathon_start:marathon_end]

    marathon_return = """    await _save(stats);
    return XpProgressService.recordMarathon(
      questionCount: questionCount,
      perfect: correct == questionCount && questionCount > 0,
    );"""

    if marathon_return not in marathon_block:
        raise RuntimeError(
            "recordMarathon entegrasyon noktası bulunamadı."
        )

    marathon_block = marathon_block.replace(
        marathon_return,
        """    await _save(stats);

    final marathonGain =
        await XpProgressService.recordMarathon(
      questionCount: questionCount,
      perfect: correct == questionCount && questionCount > 0,
    );

    final retentionGain =
        await RetentionProgressService.recordMarathon();

    if (retentionGain == null) return marathonGain;

    return XpGainResult.combine(
      <XpGainResult>[marathonGain, retentionGain],
      reason: '${marathonGain.reason} + '
          '${retentionGain.reason}',
    );""",
        1,
    )

    main = (
        main[:marathon_start]
        + marathon_block
        + main[marathon_end:]
    )

    home_marker = """                DailyChallengeHomeCard(
                  questionBank: widget.questionBank,
                ),
                const SizedBox(height: 16),
                _buildNewGameCard(),"""

    if home_marker not in main:
        raise RuntimeError(
            "Ana ekran günlük/haftalık kart ekleme noktası bulunamadı."
        )

    main = main.replace(
        home_marker,
        """                DailyChallengeHomeCard(
                  questionBank: widget.questionBank,
                ),
                const SizedBox(height: 16),
                const RetentionHomeCard(),
                const SizedBox(height: 16),
                _buildNewGameCard(),""",
        1,
    )

    reset_marker = """    await CareerStatsService.clear();
    await DailyChallengeService.clear();
    await XpProgressService.clear();"""

    if reset_marker not in main:
        raise RuntimeError(
            "İstatistik sıfırlama noktası bulunamadı."
        )

    main = main.replace(
        reset_marker,
        """    await CareerStatsService.clear();
    await DailyChallengeService.clear();
    await XpProgressService.clear();
    await RetentionProgressService.clear();""",
        1,
    )

    main, display_count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.24",
        "Bilgi Rotası • Sürüm 1.25",
        main,
        count=1,
    )

    if display_count != 1:
        raise RuntimeError(
            "Ana menü sürüm yazısı güncellenemedi."
        )

    answer_xp_start = xp.index(
        "  static Future<XpGainResult> recordAnswer({"
    )
    answer_xp_end = xp.index(
        "\n  static Future<XpGainResult> recordGameCompleted",
        answer_xp_start,
    )
    answer_xp_block = xp[
        answer_xp_start:answer_xp_end
    ]

    save_marker = """    await _save(progress);

    return XpGainResult("""

    if save_marker not in answer_xp_block:
        raise RuntimeError(
            "XP cevap kaydı lig entegrasyon noktası bulunamadı."
        )

    answer_xp_block = answer_xp_block.replace(
        save_marker,
        """    await _save(progress);
    await RetentionProgressService.recordXp(amount);

    return XpGainResult(""",
        1,
    )

    xp = (
        xp[:answer_xp_start]
        + answer_xp_block
        + xp[answer_xp_end:]
    )

    award_start = xp.index(
        "  static Future<XpGainResult> _award("
    )
    award_end = xp.index(
        "\n  static Future<void> clear()",
        award_start,
    )
    award_block = xp[award_start:award_end]

    if save_marker not in award_block:
        raise RuntimeError(
            "XP bonus kaydı lig entegrasyon noktası bulunamadı."
        )

    award_block = award_block.replace(
        save_marker,
        """    await _save(progress);
    await RetentionProgressService.recordXp(safeAmount);

    return XpGainResult(""",
        1,
    )

    xp = (
        xp[:award_start]
        + award_block
        + xp[award_end:]
    )

    pubspec = re.sub(
        r"^version:\s*.*$",
        f"version: {new_version}",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    MAIN.write_text(main, encoding="utf-8")
    XP.write_text(xp, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")

    checks = {
        MAIN: [
            "part 'retention_system.dart';",
            "RetentionProgressService.initialize",
            "RetentionProgressService.recordAnswer",
            "RetentionProgressService.recordMarathon",
            "const RetentionHomeCard()",
            "await RetentionProgressService.clear();",
            "Bilgi Rotası • Sürüm 1.25",
        ],
        XP: [
            "RetentionProgressService.recordXp(amount)",
            "RetentionProgressService.recordXp(safeAmount)",
        ],
        TARGET: [
            "class RetentionProgressService",
            "class RetentionHomeCard",
            "class RetentionHubScreen",
            "class WeeklyTask",
            "class WeeklyLeague",
            "GÜNÜN KATEGORİSİ",
            "Haftalık görevler",
        ],
        PUBSPEC: [f"version: {new_version}"],
    }

    for path, markers in checks.items():
        text = path.read_text(encoding="utf-8")

        for marker in markers:
            if marker not in text:
                raise RuntimeError(
                    f"Kurulum doğrulaması başarısız: "
                    f"{path} / {marker}"
                )

    if shutil.which("dart"):
        run([
            "dart",
            "format",
            "lib/main.dart",
            "lib/xp_progression.dart",
            "lib/retention_system.dart",
        ])

    run(["git", "diff", "--check"])

    if shutil.which("flutter"):
        run([
            "flutter",
            "analyze",
            "--no-fatal-infos",
        ])

    run([
        "git",
        "add",
        "lib/main.dart",
        "lib/xp_progression.dart",
        "lib/retention_system.dart",
        "pubspec.yaml",
    ])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0

    if not changed:
        raise RuntimeError(
            "Commit edilecek değişiklik bulunamadı."
        )

    run([
        "git",
        "commit",
        "-m",
        "Gunluk seri haftalik gorev lig ve etkinlik sistemi",
    ])
    committed = True

    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(
            backup_dir / "main.dart",
            MAIN,
        )
        shutil.copy2(
            backup_dir / "xp_progression.dart",
            XP,
        )
        shutil.copy2(
            backup_dir / "pubspec.yaml",
            PUBSPEC,
        )

        if TARGET.exists():
            TARGET.unlink()

        subprocess.run(
            [
                "git",
                "reset",
                "--",
                "lib/main.dart",
                "lib/xp_progression.dart",
                "lib/retention_system.dart",
                "pubspec.yaml",
            ],
            check=False,
        )

    print("")
    print("❌ Kurulum tamamlanamadı.")
    print(str(error))

    if committed:
        print(
            "Commit oluşturuldu fakat push başarısız oldu. "
            "Tekrar dene: git push origin main"
        )
    else:
        print(
            "Dosyalar önceki hâline otomatik döndürüldü."
        )

    raise SystemExit(1)

finally:
    shutil.rmtree(backup_dir, ignore_errors=True)

print("")
print("✅ Günlük giriş serisi ve 7 günlük XP ödülleri eklendi.")
print("✅ Günün kategorisi ve günlük +5 XP bonusu eklendi.")
print("✅ Altı haftalık görev ve otomatik XP ödülleri eklendi.")
print("✅ Bronzdan Efsaneye çevrim dışı haftalık lig eklendi.")
print("✅ Haftalık mini etkinlik ve +200 XP ödülü eklendi.")
print("✅ Bütün XP kazançları haftalık lige bağlandı.")
print("✅ Ana ekrana Günlük & Haftalık Rota kartı eklendi.")
print("✅ questions.json dosyasına dokunulmadı.")
print(f"✅ Yeni sürüm: {new_version}")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
